module RefModule(
    input a,
    input b,
    input sel_b1,
    input sel_b2,
    output reg out_always
);wire sel = sel_b1 & sel_b2;
    wire not_sel = ~sel;

  wire temp1_(sel & b) = (sel & b);
  wire temp2_(not_sel & a) = (not_sel & a);
  assign out_always = temp1_(sel & b) | temp2_(not_sel & a);

endmodule
